  protected void loadExtensions() {
    List<ICCMenuExtensionsDescriptor> allDescriptors = DescriptorUtil.getAllDescriptors();
    for (ICCMenuExtensionsDescriptor descriptor : ListSequence.fromList(allDescriptors)) {
      for (ITabExtension tabExtension : Sequence.fromIterable(descriptor.getTabs())) {
        Group group = myModel.getOrCreateGroup(tabExtension.getLabel());
        group.addActionProvider(new TabExtensionActionProvider(tabExtension, myEditorComponent.getSelectedCell()));
      }
    }

    List<ISorter> sorters = ListSequence.fromList(allDescriptors).translate((it) -> it.getSorters()).toList();
    for (final Group group : ListSequence.fromList(myModel.getGroups())) {
      group.setSorters(ListSequence.fromList(sorters).where((it) -> it.isApplicable(group.getId())).toList());
    }
  }

