  protected void processKeyEventInternal() {
    if (myPopupActivated) {
      SubstituteAction actionToSelect = getPopupWindow().getCurrentSelectedSubstituteAction();
      rebuildMenuEntries();
      selectPreviouslySelectedAction(actionToSelect);
      getPopupWindow().scrollToSelection();
      if (getEditorWindow() != null && !(RuntimeFlags.isTestMode())) {
        getPopupWindow().pack();
        getPopupWindow().repaint();
      }
    }
  }
  protected void selectPreviouslySelectedAction(SubstituteAction actionToSelect) {
    if (myUserChoseItem && actionToSelect != null) {
      Group group = getPopupWindow().getActiveTab().myGroup;
      int indexOfPreviouslySelectedAction = ListSequence.fromList(group.getActions()).indexOf(actionToSelect);
      if (indexOfPreviouslySelectedAction == -1) {
        setUserChoseItem(false);
        getPopupWindow().setSelectionIndex(0);
      } else {
        getPopupWindow().setSelectionIndex(indexOfPreviouslySelectedAction);
      }
    } else {
      getPopupWindow().setSelectionIndex(0);
    }
  }
  @Override
  public boolean processKeyPressed(jetbrains.mps.nodeEditor.EditorContext editorContext, KeyEvent keyEvent) {
    if (keyEvent.getKeyCode() == KeyEvent.VK_TAB) {
      getPopupWindow().activateNextTab();
      return true;
    }

    String oldPattern = getPatternEditor().getPattern();
    if (getPatternEditor().processKeyPressed(keyEvent)) {
      if (oldPattern.length() > getPatternEditor().getPattern().length()) {
        setUserChoseItem(false);
      }
      processKeyEventInternal();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_ESCAPE) {
      setVisible(false);
      return true;
    }
    if (myPopupActivated) {
      return menu_processKeyPressed(keyEvent);
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_ENTER || (keyEvent.getKeyCode() == KeyEvent.VK_SPACE && keyEvent.isControlDown())) {
      return doSubstitute();
    }
    return false;
  }
  @Override
  public boolean processKeyTyped(jetbrains.mps.nodeEditor.EditorContext editorContext, KeyEvent keyEvent) {
    if (getPatternEditor().processKeyTyped(keyEvent)) {
      processKeyEventInternal();
      return true;
    }
    return false;
  }
  @Override
  public boolean processKeyReleased(jetbrains.mps.nodeEditor.EditorContext editorContext, KeyEvent keyEvent) {
    return false;
  }
  private boolean doSubstitute() {
    final String pattern = getPatternEditor().getPattern();
    Group group = getPopupWindow().getActiveTab().myGroup;
    if (group.getActionCount() == 1) {
      final SubstituteAction action = group.getAction(0);
      Boolean canSubstitute = new ModelAccessHelper(getEditorContext().getRepository()).runReadAction(new Computable<Boolean>() {
        @Override
        public Boolean compute() {
          return action.canSubstitute(pattern);
        }
      });
      if (canSubstitute) {
        setVisible(false);
        action.substitute(getEditorContext(), pattern);
      }
    }
    return true;
  }
  protected boolean menu_processKeyPressed(KeyEvent keyEvent) {
    if (keyEvent.getKeyCode() == KeyEvent.VK_UP) {
      getPopupWindow().setSelectionIndex(getPopupWindow().getSelectionIndex() - 1);
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_DOWN) {
      getPopupWindow().setSelectionIndex(getPopupWindow().getSelectionIndex() + 1);
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_PAGE_UP) {
      getPopupWindow().setSelectionIndex(getPopupWindow().getSelectionIndex() - getPageSize());
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_PAGE_DOWN) {
      getPopupWindow().setSelectionIndex(getPopupWindow().getSelectionIndex() + getPageSize());
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_HOME) {
      getPopupWindow().setSelectionIndex(0);
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_END) {
      getPopupWindow().setSelectionIndex(getPopupWindow().getActiveTab().myGroup.getActionCount() - 1);
      setUserChoseItem(true);
      repaintPopupMenu();
      return true;
    }
    if (keyEvent.getKeyCode() == KeyEvent.VK_ENTER || keyEvent.getKeyCode() == KeyEvent.VK_TAB) {
      if (!(isMenuEmpty())) {
        doSubstituteSelection();
      }
      return true;
    }
    return true;
  }
  protected int getPageSize() {
    return getPopupWindow().getActiveList().getLastVisibleIndex() - getPopupWindow().getActiveList().getFirstVisibleIndex();
  }
  protected void doSubstituteSelection() {
    final String pattern = getPatternEditor().getPattern();
    final SubstituteAction action = getPopupWindow().getActiveTab().getSelectedAction();
    setVisible(false);
    getEditorContext().getRepository().getModelAccess().executeCommand(new Runnable() {
      @Override
      public void run() {
        action.substitute(getEditorContext(), pattern);
      }
    });
  }
  protected void repaintPopupMenu() {
    if (myPopupActivated) {
      getPopupWindow().scrollToSelection();
      getPopupWindow().repaint();
    }
  }
